"use strict";(self.webpackChunkrdk_s_doc=self.webpackChunkrdk_s_doc||[]).push([[324],{7800:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","label":"RDK S600 Application Cases","href":"/case_doc/en/case","docId":"case","unlisted":false},{"type":"category","label":"1. Getting Started","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"USB Peripherals","href":"/case_doc/en/getting_started/usb_peripherals","docId":"getting_started/usb_peripherals","unlisted":false},{"type":"link","label":"UART","href":"/case_doc/en/getting_started/uart","docId":"getting_started/uart","unlisted":false}],"href":"/case_doc/en/01_getting_started"},{"type":"category","label":"2. \u521d\u9636\u6848\u4f8b","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Object Detection","href":"/case_doc/en/basic/object_detection","docId":"basic/object_detection","unlisted":false},{"type":"link","label":"Voice-to-Text (ASR)","href":"/case_doc/en/basic/speech_to_text","docId":"basic/speech_to_text","unlisted":false},{"type":"link","label":"Large Language Model (LLM)","href":"/case_doc/en/basic/llm","docId":"basic/llm","unlisted":false},{"type":"link","label":"Vision-Language Model (VLM)","href":"/case_doc/en/basic/vlm","docId":"basic/vlm","unlisted":false}],"href":"/case_doc/en/02_basic"},{"type":"category","label":"3. Intermediate Cases","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Multimodal Interactive Assistant","href":"/case_doc/en/intermediate/vlm_voice_dialogue","docId":"intermediate/vlm_voice_dialogue","unlisted":false}],"href":"/case_doc/en/03_intermediate"},{"type":"category","label":"4. Advanced Cases","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Vision-Language-Action Model (VLA)","href":"/case_doc/en/advanced/vla","docId":"advanced/vla","unlisted":false}],"href":"/case_doc/en/04_advanced"},{"type":"link","label":"5. References","href":"/case_doc/en/more_resources","docId":"more_resources","unlisted":false},{"type":"link","label":"6. FAQ","href":"/case_doc/en/qa","docId":"qa","unlisted":false}]},"docs":{"advanced/vla":{"id":"advanced/vla","title":"Vision-Language-Action Model (VLA)","description":"VLA (Vision-Language-Action Model) is an end-to-end model that combines visual understanding, language interaction, and robot control. It generates robot actions directly from visual input and language instructions, and is widely used in embodied intelligence and robot manipulation. Representative work includes Google\'s RT-2 and Physical Intelligence\'s Pi0.","sidebar":"docsSidebar"},"basic/llm":{"id":"basic/llm","title":"Large Language Model (LLM)","description":"LLM (Large Language Model) is a class of AI models trained on massive text corpora with natural language understanding and generation capabilities, supporting tasks such as Q&A, translation, summarization, and code generation. Representative models include ChatGPT, GPT-4, and Qwen.","sidebar":"docsSidebar"},"basic/object_detection":{"id":"basic/object_detection","title":"Object Detection","description":"Object Detection is a core task in computer vision, primarily used to identify and locate target objects (such as people, vehicles, and animals) in images or video, typically by annotating target positions with bounding boxes. It is widely used in security surveillance, autonomous driving, industrial inspection, and similar scenarios. Representative model families include YOLO, R-CNN, and DETR.","sidebar":"docsSidebar"},"basic/speech_to_text":{"id":"basic/speech_to_text","title":"Voice-to-Text (ASR)","description":"ASR (Automatic Speech Recognition), or speech-to-text, is a technology that converts human speech into text in real time. It is a foundation for voice assistants, meeting transcription, intelligent customer service, and voice input applications.","sidebar":"docsSidebar"},"basic/vlm":{"id":"basic/vlm","title":"Vision-Language Model (VLM)","description":"VLM (Vision-Language Model) is a multimodal model that combines vision and language capabilities, understanding both image content and text semantics to enable visual understanding and language interaction. Typical applications include image Q&A, image captioning, scene understanding, and image-text retrieval.","sidebar":"docsSidebar"},"case":{"id":"case","title":"RDK S600 Application Cases","description":"This documentation collects typical application cases for the RDK S600 platform, organized by difficulty from basic peripheral integration to on-device AI inference, multimodal interaction, and embodied intelligence\u2014helping you get started quickly and dive deeper step by step.","sidebar":"docsSidebar"},"getting_started/uart":{"id":"getting_started/uart","title":"UART","description":"Overview","sidebar":"docsSidebar"},"getting_started/usb_peripherals":{"id":"getting_started/usb_peripherals","title":"USB Peripherals","description":"Overview","sidebar":"docsSidebar"},"intermediate/vlm_voice_dialogue":{"id":"intermediate/vlm_voice_dialogue","title":"Multimodal Interactive Assistant","description":"Combining ASR (Automatic Speech Recognition) with VLM (Vision-Language Model) enables \\"voice + vision\\" multimodal interaction\u2014the system understands spoken input and combines it with the current scene for semantic understanding and interaction decisions. This is widely used in robotics, smart cockpits, smart terminals, and exhibition demos.","sidebar":"docsSidebar"},"more_resources":{"id":"more_resources","title":"5. References","description":"1. For more detailed LLM case descriptions, see the RDK S600 LLM Documentation","sidebar":"docsSidebar"},"qa":{"id":"qa","title":"6. FAQ","description":"Q1 AllocError \\\\{ len: xxxx\\\\}\\"","sidebar":"docsSidebar"}}}}')}}]);